import React, { useEffect, useRef } from 'react';
import lottie from 'lottie-web';

const LottieAnimation = ({ style, src, loop }) => {
  const animationRef = useRef(null);
  const animationContainerRef = useRef(null);
  var loop = false;

  useEffect(() => {
    const options = {
      root: null,
      rootMargin: '0px',
      threshold: 0.5, // Adjust this threshold to control when the animation starts playing (0.5 means 50% visibility)
    };

    const handleIntersection = (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animationRef.current.play();
        } else {
          animationRef.current.pause();
        }
      });
    };

    const observer = new IntersectionObserver(handleIntersection, options);
    observer.observe(animationContainerRef.current);

    return () => {
      observer.unobserve(animationContainerRef.current);
    };
  }, []);

  useEffect(() => {
    if (!animationRef.current) {
      // Initialize Lottie animation if it hasn't been initialized yet
      animationRef.current = lottie.loadAnimation({
        container: animationContainerRef.current,
        renderer: 'svg',
        loop: loop,
        autoplay: false, // Set autoplay to false since we will start it based on intersection
        animationData: src, // Use the provided src prop for animation data
      });
    }
  }, [src]);

  useEffect(() => {
    if (animationRef.current) {
      animationRef.current.setSpeed(1.5);
    }
  }, []);

  return (
    <div className="lottie-container" style={style}>
      <div
        className="lottie-animation"
        ref={animationContainerRef}
        style={{ width: '350px', height: '350px' }}
      ></div>
    </div>
  );
};

export default LottieAnimation;
